async function main() {
  console.log('Starting full content seed for all 6 levels...');
  console.log('Clearing all ContentItems...');
  await prisma.contentItem.deleteMany({});
  console.log('All content items removed.');

  console.log(`Seeding ${allContent.length} content items across all 6 levels...`);

  let created = 0;
  for (const item of allContent) {
    await prisma.contentItem.create({ data: item });
    created++;
    if (created % 50 === 0) {
      console.log(`  Created ${created}/${allContent.length} items...`);
    }
  }

  console.log(`\n✅ Seed complete! Created ${created} content items.`);
  console.log('\nContent breakdown:');
  const levels = [1,2,3,4,5,6];
  for (const level of levels) {
    const count = allContent.filter(i => i.level === level).length;
    const names = ['Base Camp','Village','Town','City','Capital','World Stage'];
    console.log(`  Level ${level} (${names[level-1]}): ${count} items`);
  }
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
